using System.Reflection; using Challenger.Siem.Agent.Core.Queue; using Challenger.Siem.Agent.Core.Reliability; using Challenger.Siem.Agent.Core.Security; using Challenger.Siem.Agent.Core.Transport; using Challenger.Siem.Contracts.V1; using Challenger.Siem.LinuxAgent.Config; using Challenger.Siem.LinuxAgent.Inventory; using Microsoft.Extensions.Options;
namespace Challenger.Siem.LinuxAgent.Services;
public sealed class LinuxAgentWorker(IOptions<LinuxAgentOptions> configured,IEventQueue queue,SiemIngestClient client,LinuxEnrollmentService enrollment,ILogger<LinuxAgentWorker> logger):BackgroundService
{
 readonly LinuxAgentOptions o=configured.Value; readonly string version=Assembly.GetExecutingAssembly().GetCustomAttribute<AssemblyInformationalVersionAttribute>()?.InformationalVersion??"0.0.0";
 protected override async Task ExecuteAsync(CancellationToken ct){await enrollment.EnsureAsync(version,ct);await queue.InitializeAsync(ct);var heartbeat=DateTimeOffset.MinValue;var inventory=DateTimeOffset.MinValue;while(!ct.IsCancellationRequested){try{if(DateTimeOffset.UtcNow>=heartbeat){await client.SendHeartbeatAsync(new HeartbeatRequest{AgentId=o.AgentId,Hostname=Environment.MachineName,AgentVersion=version,Os=Environment.OSVersion.VersionString,Platform="linux",QueueDepth=await queue.CountAsync(ct),MemoryMb=(int)(GC.GetTotalMemory(false)/1024/1024),ConfigHash=AgentConfigurationHasher.ComputeConfigurationHash(Environment.GetEnvironmentVariable("CHALLENGER_SIEM_AGENT_CONFIG")??"/etc/challenger-siem-agent/agentsettings.json"),QueueMetrics=await queue.GetMetricsAsync(null,ct),SourceManifest=Array.Empty<SourceManifestEntry>(),SourceHealth=Array.Empty<SourceHealthReport>()},ct);heartbeat=DateTimeOffset.UtcNow.AddSeconds(o.HeartbeatIntervalSeconds);}if(DateTimeOffset.UtcNow>=inventory){await client.SendInventoryAsync(new[]{LinuxInventory.Collect(o.AgentId,Environment.MachineName)},ct);inventory=DateTimeOffset.UtcNow.AddSeconds(o.InventoryIntervalSeconds);}await Drain(ct);await Task.Delay(TimeSpan.FromSeconds(5),ct);}catch(OperationCanceledException)when(ct.IsCancellationRequested){break;}catch(Exception ex){logger.LogWarning("Agent transport cycle failed ({ErrorType}); queued data remains durable.",ex.GetType().Name);await Task.Delay(TimeSpan.FromSeconds(10),ct);}}}
 async Task Drain(CancellationToken ct){var batch=await queue.DequeueBatchAsync(o.DrainBatchSize,ct);if(batch.Count==0)return;var ids=batch.Select(x=>x.QueueId).ToArray();await queue.MarkAttemptAsync(ids,ct);var ack=await client.SendBatchAsync(batch.Select(x=>x.Envelope).ToArray(),ct);var accepted=IngestAcknowledgement.AcknowledgedQueueIds(batch,ack);await queue.DeleteAsync(accepted,ct);var rejected=IngestAcknowledgement.RejectedQueueIds(batch,ack);if(rejected.Length>0)await queue.MarkPoisonAsync(rejected,"server_rejected",ct);}
}
